diff --git a/llvm/lib/Transforms/InstCombine/InstCombineShifts.cpp b/llvm/lib/Transforms/InstCombine/InstCombineShifts.cpp
index 4a014ab6e044..e190e28bcb4f 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineShifts.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineShifts.cpp
@@ -1562,32 +1562,31 @@ Instruction *InstCombinerImpl::visitLShr(BinaryOperator &I) {
       return new ZExtInst(And, Ty);
     }
   }
-
-  const SimplifyQuery Q = SQ.getWithInstruction(&I);
-  if (setShiftFlags(I, Q))
-    return &I;
-
-  // Transform  (x << y) >> y  to  x & (-1 >> y)
-  if (match(Op0, m_OneUse(m_Shl(m_Value(X), m_Specific(Op1))))) {
-    Constant *AllOnes = ConstantInt::getAllOnesValue(Ty);
-    Value *Mask = Builder.CreateLShr(AllOnes, Op1);
-    return BinaryOperator::CreateAnd(Mask, X);
-  }
-
-  // Transform  (-1 << y) >> y  to -1 >> y
-  if (match(Op0, m_Shl(m_AllOnes(), m_Specific(Op1)))) {
-    Constant *AllOnes = ConstantInt::getAllOnesValue(Ty);
-    return BinaryOperator::CreateLShr(AllOnes, Op1);
+    // Reduce add-carry of masked values to logic:
+    // ((X & 1) + (Y & 1)) >> 1 --> (X & 1) & Y
+    // This is computing the average of the least significant bits.
+    // The result is 1 only when both (X & 1) and (Y & 1) are 1.
+    Value *AndOp0, *AndOp1;
+    if (ShAmtC == 1 &&
+        match(Op0, m_Add(m_Value(AndOp0), m_Value(AndOp1)))) {
+      Value *A, *B;
+      // Check for (A & 1) + (B & 1) pattern where AndOp0 = (B & 1) and AndOp1 = (A & 1)
+      // We want to return (A & 1) & B, so we use AndOp1 and A
+      if (match(AndOp0, m_OneUse(m_And(m_Value(B), m_One()))) &&
+          match(AndOp1, m_OneUse(m_And(m_Value(A), m_One())))) {
+        // Return (A & 1) & B = AndOp1 & B
+        return BinaryOperator::CreateAnd(AndOp1, B);
+      }
+      // Check for commuted pattern: (A & 1) + (B & 1) where AndOp0 = (A & 1) and AndOp1 = (B & 1)
+      if (match(AndOp1, m_OneUse(m_And(m_Value(B), m_One()))) &&
+          match(AndOp0, m_OneUse(m_And(m_Value(A), m_One())))) {
+        // Return (A & 1) & B = AndOp0 & B
+        return BinaryOperator::CreateAnd(AndOp0, B);
+      }
+    }
   }

-  if (Instruction *Overflow = foldLShrOverflowBit(I))
-    return Overflow;
-
-  return nullptr;
-}
-
-Instruction *
-InstCombinerImpl::foldVariableSignZeroExtensionOfVariableHighBitExtract(
+  const SimplifyQuery Q = SQ.getWithInstruction(&I);
     BinaryOperator &OldAShr) {
   assert(OldAShr.getOpcode() == Instruction::AShr &&
          "Must be called with arithmetic right-shift instruction only.");

